    @MainActor @objc func openFile(_ sender: Any) {
        let panel = NSOpenPanel()
        panel.allowedContentTypes = ImageFolder.supportedTypes.map { $0 }
        panel.allowsMultipleSelection = false
        panel.canChooseDirectories = false
